// FlyClean — pack de marca para el PDF de devolución (fuentes Exo 2 + logo blanco).
// Generado desde Fly/FLY1/Exo2-{Regular,Bold}.ttf (subset latin+latin-ext) e ISO-Blanco@300x.png (256px).
// Se carga on-demand vía ensureReportBrand(); CSP-safe (todo base64 local, sin fetch externo).
(function () {
  var EXO2_REGULAR = "";
  var EXO2_BOLD = "";
  var LOGO = "data:image/png;base64,";
  window.__reportBrand = {
    logo: LOGO,
    // Registra Exo 2 (normal + bold) en un documento jsPDF.
    register: function (doc) {
      doc.addFileToVFS("Exo2-Regular.ttf", EXO2_REGULAR);
      doc.addFont("Exo2-Regular.ttf", "Exo2", "normal");
      doc.addFileToVFS("Exo2-Bold.ttf", EXO2_BOLD);
      doc.addFont("Exo2-Bold.ttf", "Exo2", "bold");
    }
  };
})();
